  1	import * as React from 'react';
  2	import { connect } from 'react-redux';
  3	import { KialiDispatch } from 'types/Redux';
  4	import { ChartScatter } from '@patternfly/react-charts';
  5	import { EmptyState, EmptyStateVariant, EmptyStateBody, EmptyStateHeader } from '@patternfly/react-core';
  6	import { TracingError, JaegerTrace } from '../../types/TracingInfo';
  7	import { PFColors } from '../Pf/PfColors';
  8	import { DurationInSeconds, evalTimeRange } from 'types/Common';
  9	import { KialiAppState } from 'store/Store';
 10	import { TracingThunkActions } from 'actions/TracingThunkActions';
 11	import { LineInfo, makeLegend, VCDataPoint } from 'types/VictoryChartInfo';
 12	import { ChartWithLegend } from 'components/Charts/ChartWithLegend';
 13	import { durationSelector } from '../../store/Selectors';
 14	import { TraceTooltip } from './TraceTooltip';
 15	import { isErrorTag } from 'utils/tracing/TracingHelper';
 16	import { averageSpanDuration, buildQueriesFromSpans } from 'utils/tracing/TraceStats';
 17	import { kialiStyle } from 'styles/StyleUtils';
 18	import { MetricsStatsQuery } from 'types/MetricsOptions';
 19	import { MetricsStatsThunkActions } from 'actions/MetricsStatsThunkActions';
 20	import { TEMPO } from '../../types/Tracing';
 21	import { HistoryManager, URLParam } from '../../app/History';
 22	
 23	type ReduxProps = {
 24	  duration: DurationInSeconds;
 25	  provider?: string;
 26	  selectedTrace?: JaegerTrace;
 27	};
 28	
 29	type MapProps = {
 30	  loadMetricsStats: (queries: MetricsStatsQuery[], isCompact: boolean) => Promise<any>;
 31	  setTraceId: (cluster?: string, traceId?: string) => void;
 32	};
 33	
 34	interface TracingScatterProps {
 35	  cluster?: string;
 36	  duration: number;
 37	  errorFetchTraces?: TracingError[];
 38	  errorTraces?: boolean;
 39	  loadMetricsStats: (queries: MetricsStatsQuery[], isCompact: boolean) => Promise<any>;
 40	  provider?: string;
 41	  selectedTrace?: JaegerTrace;
 42	  setTraceId: (cluster?: string, traceId?: string) => void;
 43	  showSpansAverage: boolean;
 44	  traces: JaegerTrace[];
 45	}
 46	
 47	const ONE_MILLISECOND = 1000000;
 48	const MINIMAL_SIZE = 2;
 49	const MAXIMAL_SIZE = 30;
 50	
 51	export type JaegerLineInfo = LineInfo & { trace: JaegerTrace };
 52	type Datapoint = VCDataPoint & JaegerLineInfo;
 53	
 54	const tracingChartStyle = kialiStyle({
 55	  paddingTop: 15,
 56	  paddingLeft: 25,
 57	  paddingRight: 25,
 58	  paddingBottom: 15
 59	});
 60	
 61	const emptyStyle = kialiStyle({
 62	  display: 'flex',
 63	  justifyContent: 'center',
 64	  alignItems: 'center',
 65	  overflow: 'hidden',
 66	  // fix height + padding
 67	  height: '350px',
 68	  textAlign: 'center'
 69	});
 70	
 71	class TracingScatterComponent extends React.Component<TracingScatterProps> {
 72	  isLoading = false;
 73	  nextToLoad?: JaegerTrace = undefined;
 74	  seletedTraceMatched: number | undefined;
 75	
 76	  constructor(props: TracingScatterProps) {
 77	    super(props);
 78	    const traceId = HistoryManager.getParam(URLParam.TRACING_TRACE_ID);
 79	    if (traceId) {
 80	      this.props.setTraceId(this.props.cluster, traceId);
 81	    }
 82	  }
 83	
 84	  renderFetchEmpty = (title, msg): JSX.Element => {
 85	    return (
 86	      <div className={emptyStyle}>
 87	        <EmptyState variant={EmptyStateVariant.sm} data-test="empty-traces">
 88	          <EmptyStateHeader titleText={<>{title}</>} headingLevel="h5" />
 89	          <EmptyStateBody>{msg}</EmptyStateBody>
 90	        </EmptyState>
 91	      </div>
 92	    );
 93	  };
 94	
 95	  render(): JSX.Element {
 96	    const tracesRaw: Datapoint[] = [];
 97	    const tracesError: Datapoint[] = [];
 98	    // Tracing uses Duration instead of TimeRange, evalTimeRange is a helper here
 99	    const timeWindow = evalTimeRange({ rangeDuration: this.props.duration });
100	
101	    let traces = this.props.traces;
102	    // Add currently selected trace in list in case it wasn't
103	    if (
104	      this.props.selectedTrace &&
105	      !traces.some(t => t.traceID === this.props.selectedTrace!.traceID) &&
106	      this.props.selectedTrace.startTime >= 1000 * timeWindow[0].getTime() &&
107	      this.props.selectedTrace.startTime <= 1000 * timeWindow[1].getTime()
108	    ) {
109	      traces.push(this.props.selectedTrace);
110	    }
111	
112	    traces.forEach(trace => {
113	      const isSelected = this.props.selectedTrace && trace.traceID === this.props.selectedTrace.traceID;
114	      const traceError = trace.spans.filter(sp => sp.tags.some(isErrorTag)).length > 0;
115	      const value = this.props.showSpansAverage ? averageSpanDuration(trace) || 0 : trace.duration;
116	
117	      let spansLength;
118	      if (this.props.provider === TEMPO) {
119	        // The query to get the spans in Tempo does not return all of them,
120	        // This is to avoid the resize of the circle
121	        if (this.props.selectedTrace?.traceID === trace.traceID) {
122	          spansLength = this.seletedTraceMatched;
123	          trace.matched = this.seletedTraceMatched;
124	        } else {
125	          spansLength = trace.matched;
126	        }
127	      } else {
128	        spansLength = trace.spans.length;
129	      }
130	      const size = Math.min(MAXIMAL_SIZE, spansLength + MINIMAL_SIZE);
131	
132	      const traceItem = {
133	        x: new Date(trace.startTime / 1000),
134	        y: value / ONE_MILLISECOND,
135	        name: `${trace.traceName !== '' ? trace.traceName : '<trace-without-root-span>'} (${trace.traceID.slice(
136	          0,
137	          7
138	        )})`,
139	        color: isSelected ? PFColors.Blue500 : PFColors.Blue200,
140	        unit: 'seconds',
141	        trace: trace,
142	        size: size
143	      };
144	      if (traceError) {
145	        traceItem.color = isSelected ? PFColors.Red500 : PFColors.Red200;
146	        tracesError.push(traceItem);
147	      } else {
148	        tracesRaw.push(traceItem);
149	      }
150	    });
151	    const successTraces = {
152	      datapoints: tracesRaw,
153	      color: (({ datum }) => datum.color) as any,
154	      legendItem: makeLegend('Traces', PFColors.Blue200)
155	    };
156	
157	    const errorTraces = {
158	      datapoints: tracesError,
159	      color: (({ datum }) => datum.color) as any,
160	      legendItem: makeLegend('Error Traces', PFColors.Red200)
161	    };
162	    return this.props.errorFetchTraces && this.props.errorFetchTraces.length > 0 ? (
163	      this.renderFetchEmpty('Error fetching traces', this.props.errorFetchTraces![0].msg)
164	    ) : this.props.traces.length > 0 ? (
165	      <div data-test="tracing-scatterplot" className={tracingChartStyle}>
166	        <div style={{ marginTop: 20 }}>
167	          <ChartWithLegend<Datapoint, JaegerLineInfo>
168	            data={[successTraces, errorTraces]}
169	            fill={true}
170	            unit="seconds"
171	            seriesComponent={<ChartScatter />}
172	            onClick={dp => this.props.setTraceId(this.props.cluster, dp.trace.traceID)}
173	            onTooltipClose={dp => this.onTooltipClose(dp.trace)}
174	            onTooltipOpen={dp => this.onTooltipOpen(dp.trace)}
175	            labelComponent={<TraceTooltip />}
176	            pointer={true}
177	          />
178	        </div>
179	      </div>
180	    ) : (
181	      this.renderFetchEmpty('No traces', 'No trace results. Try another query.')
182	    );
183	  }
184	
185	  private onTooltipClose = (trace?: JaegerTrace): void => {
186	    // cancel loading the stats if we've moused out of the trace before we started loading
187	    if (trace === this.nextToLoad) {
188	      this.nextToLoad = undefined;
189	    }
190	  };
191	
192	  private loadTraceTooltipMetrics(trace: JaegerTrace): void {
193	    this.isLoading = true;
194	    if (trace.traceID !== this.props.selectedTrace?.traceID) {
195	      this.seletedTraceMatched = trace.matched;
196	    }
197	
198	    const queries = buildQueriesFromSpans(trace.spans, true);
199	
200	    this.props
201	      .loadMetricsStats(queries, true)
202	      .then(_response => {
203	        if (this.nextToLoad) {
204	          const nextTrace = this.nextToLoad;
205	          this.nextToLoad = undefined;
206	          this.loadTraceTooltipMetrics(nextTrace);
207	        } else {
208	          this.isLoading = false;
209	        }
210	      })
211	      .catch(_err => {
212	        this.isLoading = false;
213	      });
214	  }
215	
216	  private onTooltipOpen = (trace?: JaegerTrace): void => {
217	    if (!trace) {
218	      return;
219	    }
220	    if (this.isLoading) {
221	      // replace any pending load with a load for the currently hovered trace
222	      this.nextToLoad = trace;
223	    } else {
224	      this.loadTraceTooltipMetrics(trace);
225	    }
226	  };
227	}
228	
229	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
230	  duration: durationSelector(state),
231	  selectedTrace: state.tracingState.selectedTrace,
232	  provider: state.tracingState.info?.provider
233	});
234	
235	const mapDispatchToProps = (dispatch: KialiDispatch): MapProps => ({
236	  loadMetricsStats: (queries: MetricsStatsQuery[], isCompact: boolean) =>
237	    dispatch(MetricsStatsThunkActions.load(queries, isCompact)),
238	  setTraceId: (cluster?: string, traceId?: string) => dispatch(TracingThunkActions.setTraceId(cluster, traceId))
239	});
240	
241	export const TracingScatter = connect(mapStateToProps, mapDispatchToProps)(TracingScatterComponent);

